import { Component, OnInit, OnDestroy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { trigger, transition, style, animate } from '@angular/animations';
import { ParkaddaService } from '../../../../services/parkadda.service';
import { Subject } from 'rxjs';
import { takeUntil, debounceTime } from 'rxjs/operators';

interface VehicleReport {
  id: number;
  vehicleNumber: string;
  vehicleType: string;
  entryTime: string;
  exitTime: string;
  duration: string;
  parkingLocation: string;
  fee: number;
  status: string;
  rangerName: string;
}

interface ReportFilter {
  parkingId: number | null;
  fromDate: string;
  toDate: string;
  vehicleType: string;
  pageSize: number;
  currentPage: number;
}

@Component({
  selector: 'app-vehicle-reports',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './vehicle-reports.component.html',
  styleUrls: ['./vehicle-reports.component.scss'],
  animations: [
    trigger('fadeInOut', [
      transition(':enter', [
        style({ opacity: 0, transform: 'translateY(-10px)' }),
        animate('300ms ease-in', style({ opacity: 1, transform: 'translateY(0)' }))
      ]),
      transition(':leave', [
        animate('300ms ease-out', style({ opacity: 0, transform: 'translateY(-10px)' }))
      ])
    ]),
    trigger('slideIn', [
      transition(':enter', [
        style({ transform: 'translateX(400px)', opacity: 0 }),
        animate('300ms ease-out', style({ transform: 'translateX(0)', opacity: 1 }))
      ])
    ])
  ]
})
export class VehicleReportsComponent implements OnInit, OnDestroy {
  vehicleReports: VehicleReport[] = [];
  inReports: VehicleReport[] = [];
  outReports: VehicleReport[] = [];
  allReports: VehicleReport[] = [];
  filteredReports: VehicleReport[] = [];

  loading = false;
  selectedReportType = 'in'; // 'in', 'out', 'all'
  searchTerm = '';
  selectedReport: VehicleReport | null = null;
  showDetailsModal = false;
  toasts: Array<{ message: string; type: string }> = [];

  parkings: Array<{ id: number; name: string }> = [];
  currentPage = 1;
  pageSize = 10;
  totalCount = 0;
  totalPages = 1;

  filter: ReportFilter = {
    parkingId: null,
    fromDate: this.getFormattedDate(new Date(new Date().setDate(new Date().getDate() - 30))),
    toDate: this.getFormattedDate(new Date()),
    vehicleType: '',
    pageSize: 10,
    currentPage: 1
  };

  private destroy$ = new Subject<void>();
  private searchSubject$ = new Subject<string>();

  constructor(private parkaddaService: ParkaddaService) {}

  ngOnInit() {
    this.loadParkings();
    this.loadVehicleReports();

    // Subscribe to search changes with debounce
    this.searchSubject$
      .pipe(
        debounceTime(300),
        takeUntil(this.destroy$)
      )
      .subscribe(() => {
        this.filterReports();
      });
  }

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

  loadParkings() {
    this.parkaddaService.getParkingList()
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (response: any) => {
          const parkingData = response.data || [];
          this.parkings = parkingData.map((p: any) => ({
            id: p.parking_table_id || p.id,
            name: p.parking_name || p.name
          }));
          if (this.parkings.length > 0) {
            this.filter.parkingId = (response.data?.[0]?.parking_table_id || response.data?.[0]?.id) as number;
          }
        },
        error: (error: any) => {
          console.error('Error loading parkings:', error);
          this.showToast('Error loading parkings', 'error');
        }
      });
  }

  loadVehicleReports() {
    if (!this.filter.parkingId) {
      this.showToast('Please select a parking location', 'warning');
      return;
    }

    this.loading = true;
    const params = {
      page: this.filter.currentPage,
      page_size: this.filter.pageSize,
      parking_table_id: this.filter.parkingId,
      from_date_filter: this.filter.fromDate,
      to_date_filter: this.filter.toDate
    };

    // Load all report types
    Promise.all([
      this.parkaddaService.searchAdminVehicleInReports(params).toPromise(),
      this.parkaddaService.searchAdminVehicleOutReports(params).toPromise(),
      this.parkaddaService.searchAdminVehicleReports(params).toPromise()
    ])
      .then(([inRes, outRes, allRes]: any[]) => {
        this.inReports = inRes?.data?.results || [];
        this.outReports = outRes?.data?.results || [];
        this.allReports = allRes?.data?.results || [];

        this.updateDisplayedReports();
        this.totalCount = allRes?.data?.total_count || 0;
        this.totalPages = Math.ceil(this.totalCount / this.filter.pageSize);
        this.loading = false;
      })
      .catch((error) => {
        console.error('Error loading vehicle reports:', error);
        this.showToast('Error loading vehicle reports', 'error');
        this.loading = false;
      });
  }

  updateDisplayedReports() {
    switch (this.selectedReportType) {
      case 'in':
        this.vehicleReports = this.inReports;
        break;
      case 'out':
        this.vehicleReports = this.outReports;
        break;
      case 'all':
        this.vehicleReports = this.allReports;
        break;
      default:
        this.vehicleReports = this.allReports;
    }
    this.filterReports();
  }

  onReportTypeChange() {
    this.currentPage = 1;
    this.updateDisplayedReports();
  }

  onFilterChange() {
    this.currentPage = 1;
    this.loadVehicleReports();
  }

  onSearchChange() {
    this.searchSubject$.next(this.searchTerm);
  }

  filterReports() {
    this.filteredReports = this.vehicleReports.filter(report => {
      const matchesSearch = !this.searchTerm ||
        report.vehicleNumber.toLowerCase().includes(this.searchTerm.toLowerCase()) ||
        report.parkingLocation.toLowerCase().includes(this.searchTerm.toLowerCase()) ||
        report.rangerName.toLowerCase().includes(this.searchTerm.toLowerCase());

      const matchesVehicleType = !this.filter.vehicleType ||
        report.vehicleType === this.filter.vehicleType;

      return matchesSearch && matchesVehicleType;
    });
  }

  viewDetails(report: VehicleReport) {
    this.selectedReport = report;
    this.showDetailsModal = true;
  }

  closeDetailsModal() {
    this.showDetailsModal = false;
    this.selectedReport = null;
  }

  exportToCSV() {
    if (this.filteredReports.length === 0) {
      this.showToast('No data to export', 'warning');
      return;
    }

    const headers = ['Vehicle Number', 'Type', 'Entry Time', 'Exit Time', 'Duration', 'Location', 'Fee', 'Status'];
    const rows = this.filteredReports.map(r => [
      r.vehicleNumber,
      r.vehicleType,
      r.entryTime,
      r.exitTime || '-',
      r.duration || '-',
      r.parkingLocation,
      r.fee,
      r.status
    ]);

    let csvContent = headers.join(',') + '\n';
    rows.forEach(row => {
      csvContent += row.map(cell => `"${cell}"`).join(',') + '\n';
    });

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `vehicle-reports-${new Date().getTime()}.csv`;
    a.click();
    window.URL.revokeObjectURL(url);

    this.showToast('Report exported successfully', 'success');
  }

  nextPage() {
    if (this.currentPage < this.totalPages) {
      this.currentPage++;
      this.filter.currentPage = this.currentPage;
      this.loadVehicleReports();
    }
  }

  previousPage() {
    if (this.currentPage > 1) {
      this.currentPage--;
      this.filter.currentPage = this.currentPage;
      this.loadVehicleReports();
    }
  }

  private showToast(message: string, type: string) {
    this.toasts.push({ message, type });
    setTimeout(() => {
      this.toasts.shift();
    }, 3000);
  }

  getToastIcon(type: string): string {
    switch (type) {
      case 'success':
        return 'fa-check-circle';
      case 'error':
        return 'fa-exclamation-circle';
      case 'warning':
        return 'fa-exclamation-triangle';
      case 'info':
        return 'fa-info-circle';
      default:
        return 'fa-info-circle';
    }
  }

  getStatusClass(status: string): string {
    switch (status.toLowerCase()) {
      case 'active':
        return 'status-active';
      case 'completed':
        return 'status-completed';
      case 'pending':
        return 'status-pending';
      default:
        return 'status-default';
    }
  }

  private getFormattedDate(date: Date): string {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  }
}
